// helper: get western zodiac index from day/month
window.HR.getWesternIdx = function(d,m){
  const b=[[1,20],[2,19],[3,20],[4,20],[5,21],[6,21],[7,23],[8,23],[9,23],[10,23],[11,22],[12,22]];
  let i=m-1;if(d<b[m-1][1])i=(m-2+12)%12;return i;
};

