// helper: get Mayan day sign
window.HR.getMayan = function(d,m,y){
  const base=new Date(1980,0,1);
  const diff=Math.floor((new Date(y,m-1,d)-base)/86400000);
  const idx=((diff%20)+20)%20;
  const tone=((diff%13)+13)%13+1;
  return {sign:window.HR.MAYAN_SIGNS[idx], tone};
};

