window.HR.getNakshatra = function(d,m,y){
  const base=new Date(1900,0,1);
  const diff=Math.floor((new Date(y,m-1,d)-base)/86400000);
  return window.HR.NAKSHATRA[((diff%27)+27)%27];
};

