window.HR.getCeltic = function(d,m){
  for(const t of window.HR.CELTIC){
    for(const r of t.r){
      if(m===r.s&&d>=r.sd)return t;
      if(m===r.em&&d<=r.ed)return t;
    }
  }
  return window.HR.CELTIC[0];
};

